1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSE_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOWUP_CONTRACT_DISCOUNT_RATE = 0.15;
9	const DEDUCTIBLE = 100;
10	const CAP_MULTIPLIER = 2;
11	
12	const INSURANCE_VALUE_BY_ITEM_TYPE: Record<string, number> = {
13	  sword: 1000,
14	  amulet: 600,
15	  staff: 800,
16	  potion: 400,
17	  rune: 250,
18	  moonstone: 250,
19	};
20	const COMPONENT_BASE_PRICE = 25;
21	const COMPONENT_BLOCK_SIZE = 3;
22	const COMPONENT_BLOCK_PRICE = 60;
23	
24	const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	};
30	
31	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
32	
33	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
34	type Customer = { yearsWithMHPCO: number };
35	
36	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
37	
38	const mainItemBasePrice = (item: Item): number =>
39	  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
40	
41	const componentGroupBasePrice = (count: number): number =>
42	  count === COMPONENT_BLOCK_SIZE
43	    ? COMPONENT_BLOCK_PRICE
44	    : count * COMPONENT_BASE_PRICE;
45	
46	const groupComponentsByType = (items: Item[]): Map<string, number> => {
47	  const groups = new Map<string, number>();
48	  for (const item of items) {
49	    if (!isComponent(item)) continue;
50	    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
51	  }
52	  return groups;
53	};
54	
55	const sum = (numbers: number[]): number =>
56	  numbers.reduce((total, n) => total + n, 0);
57	
58	const policyBasePremium = (items: Item[]): number => {
59	  const mainItemPremiums = items
60	    .filter((item) => !isComponent(item))
61	    .map(mainItemBasePrice);
62	  const componentGroupPremiums = [...groupComponentsByType(items).values()].map(
63	    componentGroupBasePrice,
64	  );
65	  return sum([...mainItemPremiums, ...componentGroupPremiums]);
66	};
67	
68	const curseSurcharge = (item: Item): number =>
69	  item.cursed ? mainItemBasePrice(item) * CURSE_SURCHARGE_RATE : 0;
70	
71	const highEnchantmentSurcharge = (item: Item): number =>
72	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
73	    ? mainItemBasePrice(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
74	    : 0;
75	
76	const itemSurcharges = (items: Item[]): number =>
77	  sum(items.map((item) => curseSurcharge(item) + highEnchantmentSurcharge(item)));
78	
79	const loyaltyDiscount = (customer: Customer, basePremium: number): number =>
80	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
81	    ? basePremium * LOYALTY_DISCOUNT_RATE
82	    : 0;
83	
84	type QuoteContext = { contractIndex?: number };
85	
86	const followUpDiscount = (
87	  context: QuoteContext,
88	  basePremium: number,
89	): number =>
90	  (context.contractIndex ?? 0) >= 1
91	    ? basePremium * FOLLOWUP_CONTRACT_DISCOUNT_RATE
92	    : 0;
93	
94	export const quote = (
95	  customer: Customer,
96	  items: Item[],
97	  context: QuoteContext = {},
98	): number => {
99	  const basePremium = policyBasePremium(items);
100	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
101	  return Math.ceil(
102	    basePremium +
103	      firstInsuranceSurcharge -
104	      loyaltyDiscount(customer, basePremium) -
105	      followUpDiscount(context, basePremium) +
106	      itemSurcharges(items) +
107	      PROCESSING_FEE,
108	  );
109	};
110	
111	type Policy = { items: Item[] };
112	type Damage = { itemType: string; amount: number };
113	type Incident = { cause?: string; damages: Damage[] };
114	type ClaimResult = { payout: number; remainingCap: number };
115	
116	const policyInsuranceSum = (policy: Policy): number =>
117	  sum(policy.items.map((item) => INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0));
118	
119	const policyCap = (policy: Policy): number =>
120	  policyInsuranceSum(policy) * CAP_MULTIPLIER;
121	
122	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
123	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
124	
125	const findPolicyItem = (policy: Policy, itemType: string): Item | undefined =>
126	  policy.items.find((item) => item.type === itemType);
127	
128	const reimbursableAmount = (item: Item | undefined, amount: number): number =>
129	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
130	    ? amount * HIGH_ENCHANTMENT_PAYOUT_RATE
131	    : amount;
132	
133	const payoutForDamage = (policy: Policy, damage: Damage): number =>
134	  Math.max(
135	    0,
136	    reimbursableAmount(findPolicyItem(policy, damage.itemType), damage.amount) -
137	      DEDUCTIBLE,
138	  );
139	
140	export const claim = (
141	  policy: Policy,
142	  incident: Incident,
143	  alreadyPaid: number = 0,
144	): ClaimResult => {
145	  const cap = policyCap(policy);
146	  const remainingBefore = cap - alreadyPaid;
147	  const desiredPayout = sum(
148	    incident.damages.map((damage) => payoutForDamage(policy, damage)),
149	  );
150	  const payout = Math.min(desiredPayout, remainingBefore);
151	  const remainingCap = remainingBefore - payout;
152	  return { payout: Math.floor(payout), remainingCap };
153	};
